class Bar {}
public class Foo extends Bar implements Cloneable{
    void clone() {}
}

public class Foo {
    final Object clone() throws CloneNotSupportedException {
        CloneNotSupportedException e = new CloneNotSupportedException();
        throw e;
    }
}

public class Foo {
    final Object clone() throws CloneNotSupportedException {
        System.out.println("clone is not supported");
        throw new CloneNotSupportedException();
    }
}

public class Foo {
    final Object clone() throws CloneNotSupportedException {
        try {
            logAttempt();
        } catch (RuntimeException ignored) {
            // ignore
        }
        throw new CloneNotSupportedException();
    }
    private void logAttempt() {}
}

public class Foo {
    final Object clone() {
        System.out.println("clone called");
    }
}

public class Foo {
    Object clone() throws Exception {
        try {
            doSomething();
        } catch (java.io.IOException e) {
            throw new RuntimeException(e);
        }
        throw new CloneNotSupportedException();
    }
    private void doSomething() throws java.io.IOException {}
}

public class Foo {
    Object clone() throws CloneNotSupportedException {
        if (System.currentTimeMillis() < 0) {
            throw new CloneNotSupportedException();
        }
        return null;
    }
}

public class Foo {
    final Object clone() throws CloneNotSupportedException {
        Runnable r = () -> {
            return;
        };
        throw new CloneNotSupportedException();
    }
}

public class Foo {
    final Object clone() throws CloneNotSupportedException {
        if (System.currentTimeMillis() > 0) {
            throw new CloneNotSupportedException("a");
        } else {
            throw new CloneNotSupportedException("b");
        }
    }
}

public class Foo {
    public final Object clone() throws CloneNotSupportedException {
        throw new CloneNotSupportedException();
    }
}

public final class Foo {
    public Object clone() throws CloneNotSupportedException {
        throw new CloneNotSupportedException();
    }
}

public class MyAbstractClass implements Cloneable{
}
public class MyCloneableClass extends MyAbstractClass{
    protected Object clone() throws CloneNotSupportedException {
        return super.clone();
    }
}

